module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const palette = ['#3b82f6', '#ef4444', '#22c55e', '#f59e0b', '#8b5cf6', '#06b6d4', '#ec4899', '#64748b'];
const rotate = String(args.rotate) !== 'false';
const hash = (s) => { let h = 5381; for (let i = 0; i < s.length; i++) h = ((h << 5) + h + s.charCodeAt(i)) >>> 0; return h; };
const words = [];
sections.join('\n').split('\n').map((l) => l.trim()).filter(Boolean).forEach((l) => {
  const m = l.match(/^(.*?)\s+(\d+(?:\.\d+)?)$/);
  if (m) words.push({ w: m[1].trim(), v: parseFloat(m[2]) });
  else words.push({ w: l, v: 1 });
});
if (!words.length) return `<div>(wordcloud: one "word weight" per line)</div>`;
const lo = Math.min(...words.map((x) => x.v)), hi = Math.max(...words.map((x) => x.v));
const scRaw = parseFloat(args.scale);
const sc = Number.isFinite(scRaw) && scRaw > 0 ? scRaw : 1;
const size = (v) => (0.85 + (hi === lo ? 0.6 : ((v - lo) / (hi - lo)) * 1.9)) * sc; // em
// deterministic interleave: spread big words through the flow
const sorted = words.slice().sort((a, b) => b.v - a.v);
const arranged = [];
sorted.forEach((w, i) => { if (i % 2 === 0) arranged.push(w); else arranged.unshift(w); });
const alignKey = String(args.align || 'center').toLowerCase();
const justify = alignKey === 'left' ? 'flex-start' : alignKey === 'right' ? 'flex-end' : 'center';
const gap = (args.gap || '6px 4px').trim() || '6px 4px';
const maxW = (args.maxwidth || '620px').trim() || '620px';
let html = `\n\n<div class="mdp-mod-wordcloud" style="--wc-justify:${justify}; --wc-gap:${gap}; --wc-mw:${maxW};">`;
arranged.forEach((x) => {
  const h = hash(x.w);
  const c = args.color || palette[h % palette.length];
  const rot = rotate && (h % 5 === 0) ? (h % 2 ? -90 : 90) : 0;
  const pad = (h % 3) * 4;
  html += `<span class="mdp-wc-word" style="font-size:${size(x.v).toFixed(2)}em; color:${c}; margin:0 ${4 + pad}px;${rot ? ` writing-mode:vertical-rl;${rot < 0 ? ' transform:rotate(180deg);' : ''}` : ''}">${esc(x.w)}</span>`;
});
html += `</div>\n\n`;
return html;
